+        // (e.g., it's a validity bitmap which has rows/8 bytes = 0.125 bytes per row)
+        if (bytesPerOffset !== 4 && bytesPerOffset !== 8) {
+            throw new Error(`Not a string column - bytesPerOffset=${bytesPerOffset}, expected 4 or 8`);
